#define BLOCK_SIZE 16

#define MAX_PD	(3.0e6)
#define PRECISION	0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI 100
#define FACTOR_CHIP	0.5

const float t_chip = 0.0005;
const float chip_height = 0.016;
const float chip_width = 0.016;
const float amb_temp = 80.0;

__kernel void hotspot(
    int iter,
    __global const float* power,
    __global const float* temp_in,
    __global float* temp_out,
    int col,
    int row,
    int borderCols,
    int borderRows,
    float Cap,
    float Rx,
    float Ry,
    float Rz,
    float step)
{
    float Rx_1 = 1.0f / Rx;
    float Ry_1 = 1.0f / Ry;
    float Rz_1 = 1.0f / Rz;
    float Cap_1 = step / Cap;

    int blockId_x = get_group_id(0);
    int blockId_y = get_group_id(1);
    int local_x = get_local_id(0);
    int local_y = get_local_id(1);

    int c_start = blockId_x * BLOCK_SIZE;
    int r_start = blockId_y * BLOCK_SIZE;

    int c = c_start + local_x;
    int r = r_start + local_y;

    if (r >= row || c >= col) return;

    for (int i = 0; i < iter; i++) {
        float delta;
        int idx = r * col + c;

        if (r == 0 && c == 0) {
            delta = Cap_1 * (power[idx] +
                (temp_in[idx + 1] - temp_in[idx]) * Rx_1 +
                (temp_in[idx + col] - temp_in[idx]) * Ry_1 +
                (amb_temp - temp_in[idx]) * Rz_1);
        }
        else if (r == 0 && c == col - 1) {
            delta = Cap_1 * (power[idx] +
                (temp_in[idx - 1] - temp_in[idx]) * Rx_1 +
                (temp_in[idx + col] - temp_in[idx]) * Ry_1 +
                (amb_temp - temp_in[idx]) * Rz_1);
        }
        else if (r == row - 1 && c == col - 1) {
            delta = Cap_1 * (power[idx] +
                (temp_in[idx - 1] - temp_in[idx]) * Rx_1 +
                (temp_in[idx - col] - temp_in[idx]) * Ry_1 +
                (amb_temp - temp_in[idx]) * Rz_1);
        }
        else if (r == row - 1 && c == 0) {
            delta = Cap_1 * (power[idx] +
                (temp_in[idx + 1] - temp_in[idx]) * Rx_1 +
                (temp_in[idx - col] - temp_in[idx]) * Ry_1 +
                (amb_temp - temp_in[idx]) * Rz_1);
        }
        else if (r == 0) {
            delta = Cap_1 * (power[idx] +
                (temp_in[idx + 1] + temp_in[idx - 1] - 2.0f * temp_in[idx]) * Rx_1 +
                (temp_in[idx + col] - temp_in[idx]) * Ry_1 +
                (amb_temp - temp_in[idx]) * Rz_1);
        }
        else if (c == col - 1) {
            delta = Cap_1 * (power[idx] +
                (temp_in[idx + col] + temp_in[idx - col] - 2.0f * temp_in[idx]) * Ry_1 +
                (temp_in[idx - 1] - temp_in[idx]) * Rx_1 +
                (amb_temp - temp_in[idx]) * Rz_1);
        }
        else if (r == row - 1) {
            delta = Cap_1 * (power[idx] +
                (temp_in[idx + 1] + temp_in[idx - 1] - 2.0f * temp_in[idx]) * Rx_1 +
                (temp_in[idx - col] - temp_in[idx]) * Ry_1 +
                (amb_temp - temp_in[idx]) * Rz_1);
        }
        else if (c == 0) {
            delta = Cap_1 * (power[idx] +
                (temp_in[idx + col] + temp_in[idx - col] - 2.0f * temp_in[idx]) * Ry_1 +
                (temp_in[idx + 1] - temp_in[idx]) * Rx_1 +
                (amb_temp - temp_in[idx]) * Rz_1);
        }
        else {
            delta = Cap_1 * (power[idx] +
                (temp_in[idx + col] + temp_in[idx - col] - 2.0f * temp_in[idx]) * Ry_1 +
                (temp_in[idx + 1] + temp_in[idx - 1] - 2.0f * temp_in[idx]) * Rx_1 +
                (amb_temp - temp_in[idx]) * Rz_1);
        }

        temp_out[idx] = temp_in[idx] + delta;
    }
}
